// src/components/SearchResults.astro
---
interface Result {
  category: string
  components?: number
  description?: string
  slug: string
  terms: string[]
  title: string
}

interface Props {
  collections: Result[]
  posts: Result[]
}

const { collections, posts } = Astro.props
---

<search-results data-collections={JSON.stringify(collections)} data-posts={JSON.stringify(posts)}>
  <div
    data-container="false"
    class="absolute top-full right-0 z-50 mt-2 w-64 overflow-hidden rounded-lg border border-gray-200 bg-white shadow-lg data-[container=false]:hidden data-[container=true]:block md:w-80"
  >
    <p data-error="false" class="px-4 py-2 text-gray-700 data-[error=false]:hidden">
      No results found.
    </p>

    <div data-list class="max-h-96 divide-y divide-gray-200 overflow-y-auto"></div>
  </div>

  <span data-status aria-live="polite" class="sr-only"></span>
</search-results>

<script>
  interface Result {
    category: string
    components?: number
    description?: string
    slug: string
    terms: string[]
    title: string
  }

  class SearchResults extends HTMLElement {
    private collectionItems: Result[] = []
    private postItems: Result[] = []

    private searchResults: Result[] = []

    private enterHandler: (() => void) | null = null
    private escapeHandler: (() => void) | null = null
    private searchHandler: ((event: CustomEvent<{ value: string }>) => void) | null = null

    private resetResults(resultsEl: HTMLElement) {
      resultsEl.replaceChildren()
    }

    private normalizePath(slug: string): string {
      try {
        const candidateUrl = new URL(slug, globalThis.location.origin)

        if (candidateUrl.origin !== globalThis.location.origin) {
          return '/'
        }

        return `${candidateUrl.pathname}${candidateUrl.search}${candidateUrl.hash}`
      } catch {
        return '/'
      }
    }

    private createResultItem(result: Result): HTMLLIElement {
      const listItem = document.createElement('li')

      listItem.setAttribute('role', 'option')

      const anchorEl = document.createElement('a')

      anchorEl.setAttribute('href', this.normalizePath(result.slug))
      anchorEl.className = 'block px-4 py-3 hover:bg-gray-50'

      const contentEl = document.createElement('div')

      contentEl.className = 'flex items-center justify-between gap-2'

      const titleEl = document.createElement('h3')

      titleEl.className = 'text-sm text-gray-900 font-medium'
      titleEl.textContent = result.title

      contentEl.appendChild(titleEl)

      if (result.category) {
        const categoryEl = document.createElement('span')

        categoryEl.className = 'text-xs text-gray-500 shrink-0 capitalize'
        categoryEl.textContent = result.category

        contentEl.appendChild(categoryEl)
      }

      anchorEl.appendChild(contentEl)

      if (result.components) {
        const componentCountEl = document.createElement('p')

        componentCountEl.className = 'text-xs text-gray-500 mt-0.5'
        componentCountEl.textContent = `${result.components} components`

        anchorEl.appendChild(componentCountEl)
      }

      listItem.appendChild(anchorEl)

      return listItem
    }

    private createResultSection(title: string, items: Result[]): HTMLDivElement {
      const titleEl = document.createElement('strong')

      titleEl.className = 'px-3 py-2 text-xs font-medium text-gray-500 bg-gray-50 block'
      titleEl.textContent = title

      const listEl = document.createElement('ul')

      listEl.setAttribute('role', 'listbox')
      listEl.className = 'divide-y divide-gray-200 border-t border-gray-200'

      items.forEach((item) => {
        listEl.appendChild(this.createResultItem(item))
      })

      const sectionEl = document.createElement('div')

      sectionEl.appendChild(titleEl)
      sectionEl.appendChild(listEl)

      return sectionEl
    }

    private renderResults(resultsEl: HTMLElement, collections: Result[], posts: Result[]) {
      const fragment = document.createDocumentFragment()

      if (collections.length > 0) {
        fragment.appendChild(this.createResultSection('Components', collections))
      }

      if (posts.length > 0) {
        fragment.appendChild(this.createResultSection('Blog Posts', posts))
      }

      resultsEl.replaceChildren(fragment)
    }

    connectedCallback() {
      const containerEl = this.querySelector('[data-container]') as HTMLElement | null
      const errorEl = this.querySelector('[data-error]') as HTMLElement | null
      const resultsEl = this.querySelector('[data-list]') as HTMLElement | null
      const statusEl = this.querySelector('[data-status]') as HTMLElement | null

      if (!containerEl || !errorEl || !resultsEl || !statusEl) {
        return
      }

      try {
        this.collectionItems = JSON.parse(this.dataset.collections || '[]')
        this.postItems = JSON.parse(this.dataset.posts || '[]')
      } catch {
        return
      }

      this.enterHandler = () => {
        if (this.searchResults.length !== 1) {
          return
        }

        const [searchResult] = this.searchResults

        if (!searchResult) {
          return
        }

        const returnUrl = new URL(searchResult.slug, globalThis.location.href)

        globalThis.location.href = returnUrl.toString()
      }

      this.escapeHandler = () => {
        this.searchResults = []

        this.resetResults(resultsEl)

        containerEl.setAttribute('data-container', 'false')
        errorEl.setAttribute('data-error', 'false')
      }

      this.searchHandler = (searchEvent) => {
        const searchQuery = searchEvent.detail.value.toLowerCase()

        if (!searchQuery) {
          this.searchResults = []

          this.resetResults(resultsEl)

          containerEl.setAttribute('data-container', 'false')
          errorEl.setAttribute('data-error', 'false')

          return
        }

        containerEl.setAttribute('data-container', 'true')

        const filterResults = (items: Result[]) => {
          return items.filter((potentialResult) => {
            const searchableText = [
              potentialResult.description || '',
              potentialResult.title,
              ...(potentialResult.terms || []),
            ]
              .join(' ')
              .toLowerCase()

            return searchableText.includes(searchQuery)
          })
        }

        const filteredCollections = filterResults(this.collectionItems)
        const filteredPosts = filterResults(this.postItems)

        const totalResults = filteredCollections.length + filteredPosts.length

        if (totalResults === 0) {
          this.searchResults = []

          this.resetResults(resultsEl)
          statusEl.textContent = 'No results found'

          errorEl.setAttribute('data-error', 'true')

          return
        }

        this.searchResults = [...filteredCollections, ...filteredPosts]

        statusEl.textContent = `${totalResults} ${totalResults === 1 ? 'result' : 'results'} found`

        this.renderResults(resultsEl, filteredCollections, filteredPosts)

        errorEl.setAttribute('data-error', 'false')
      }

      document.addEventListener('input:enter', this.enterHandler)
      document.addEventListener('input:escape', this.escapeHandler)
      // @ts-expect-error -- CustomEvent handler is not assignable to EventListener
      document.addEventListener('input:search', this.searchHandler)
    }

    disconnectedCallback() {
      if (this.enterHandler && this.escapeHandler && this.searchHandler) {
        document.removeEventListener('input:enter', this.enterHandler)
        document.removeEventListener('input:escape', this.escapeHandler)
        // @ts-expect-error -- CustomEvent handler is not assignable to EventListener
        document.removeEventListener('input:search', this.searchHandler)

        this.enterHandler = null
        this.escapeHandler = null
        this.searchHandler = null
      }

      this.collectionItems = []
      this.postItems = []
    }
  }

  customElements.define('search-results', SearchResults)
</script>

